<?php
require_once __DIR__ . '/../config/database.php'; require_once __DIR__ . '/../includes/functions.php'; require_admin();
if(isset($_GET['delete'])){$stmt=$pdo->prepare('DELETE FROM gallery WHERE id=?');$stmt->execute([(int)$_GET['delete']]);redirect('admin/gallery.php');}
if($_SERVER['REQUEST_METHOD']==='POST'){$img=upload_image('image'); if($img){$stmt=$pdo->prepare('INSERT INTO gallery (event_id,title,image,caption) VALUES (?,?,?,?)');$stmt->execute([$_POST['event_id']?:null,$_POST['title'],$img,$_POST['caption']]);}redirect('admin/gallery.php');}
$events=$pdo->query('SELECT id,title FROM events ORDER BY title')->fetchAll();$items=$pdo->query('SELECT * FROM gallery ORDER BY created_at DESC')->fetchAll();$title='Kelola Galeri';require_once __DIR__ . '/_layout.php';
?>
<div class="grid grid-2"><form class="card card-body" method="post" enctype="multipart/form-data"><h2>Upload Galeri</h2><div class="form-row"><label class="label">Judul</label><input class="input" name="title" required></div><div class="form-row"><label class="label">Event</label><select name="event_id"><option value="">Tanpa Event</option><?php foreach($events as $e): ?><option value="<?= $e['id'] ?>"><?= e($e['title']) ?></option><?php endforeach; ?></select></div><div class="form-row"><label class="label">Caption</label><input class="input" name="caption"></div><div class="form-row"><label class="label">Foto</label><input class="input" type="file" name="image" accept="image/*" required></div><button class="btn btn-primary">Upload</button></form><div class="gallery"><?php foreach($items as $g): ?><figure><img src="../<?= e($g['image']) ?>" alt=""><figcaption><?= e($g['title']) ?><br><a onclick="return confirm('Hapus?')" href="?delete=<?= $g['id'] ?>">Hapus</a></figcaption></figure><?php endforeach; ?></div></div>
